def diff(fx: list): #求导
    n = len(fx)
    if n == 0:
        return float('nan')
    elif n == 1:
        return [0]
    return [fx[i] * (n - 1 - i) for i in range(n - 1)]
def polyval(f: list, x): #代入求值
    n = len(f)
    if n == 0:
        return float('nan')
    elif n == 1:
        return f[0]
    return sum(coef * x ** (n - 1 - i) for i, coef in enumerate(f))
def newton_solver(fx: list, x0, depth, tol): #牛顿法
    x = x0
    fpx = diff(fx)
    for i in range(depth):
        val_fx = polyval(fx, x)
        if abs(val_fx) < tol:
            return x
        if abs(x) > 1e8:
            raise ValueError("the iteration diverges")
        val_fpx = polyval(fpx, x)
        if val_fpx == 0:
            raise ValueError("the derivative is zero so cannot iterate")
        x = x - val_fx / val_fpx
    return x
def inequality_larger(a, b): #ax+b>0
    if a==0:
        return float('nan')
    elif a>0:
        return f"x>{-b/a}"
    elif a<0:
        return f"x<{-b/a}"
def inequality_larger_and_equal(a, b): #ax+b≥0
    if a==0:
        return float('nan')
    elif a>0:
        return f"x≥{-b/a}"
    elif a<0:
        return f"x≤{-b/a}"
def inequality_lower_and_equal(a, b): #ax+b≤0
    if a==0:
        return float('nan')
    elif a>0:
        return f"x≤{-b/a}"
    elif a<0:
        return f"x≥{-b/a}"
def inequality_lower(a, b): #ax+b<0
    if a==0:
        return float('nan')
    elif a>0:
        return f"x<{-b/a}"
    elif a<0:
        return f"x>{-b/a}"
def inequality(a, b, sym: str): #不等式统一接口
    if sym==">":
        return inequality_larger(a, b)
    elif sym==">=":
        return inequality_larger_and_equal(a, b)
    elif sym=="<=":
        return inequality_lower_and_equal(a, b)
    elif sym=="<":
        return inequality_lower(a, b)
    else:
        raise NotImplementedError("don't support this type of parameter")
def solve(*args): #统一求解函数接口
    if len(args)==2: #双参数->一元一次
        a, b = args
        return solve_linear_equation_in_one_unknown(a, b)
    elif len(args)==3: #三参数->一元二次/不等式
        if isinstance(args[2], str): #第三参数是字符串->不等式
            a, b, sym = args
            return inequality(a, b, sym)
        else: #第三参数不是字符串->一元二次
            a, b, c = args
            return solve_quadratic_equation(a, b, c)
    elif len(args)==4: #四参数->一元三次/牛顿法
        if isinstance(args[0], list): #第一参数为列表->牛顿法
            fx, x0, depth, tol = args
            return newton_solver(fx, x0, depth, tol)
        else: #第一参数不是列表->一元三次
            a, b, c, d = args
            return solve_cubic_equation_in_one_unknown(a, b, c, d)
    elif len(args)==5: #五参数->一元四次
        a, b, c, d, e = args
        return solve_quartic_equation(a, b, c, d, e)
    else: #都不是->不支持,报错
        raise NotImplementedError("don't support this type of parameter")
